@code {
    [CascadingParameter] private HttpContext HttpContext { get; set; } = default!;

    private IComponentRenderMode? pageRenderMode;

    protected override void OnInitialized()
    {
        // Pages marked with [ExcludeFromInteractiveRouting] render as static SSR
        // (needed for auth pages that require HttpContext). Everything else stays interactive.
        var isStaticPage = HttpContext.GetEndpoint()?.Metadata
            .OfType<ExcludeFromInteractiveRoutingAttribute>().Any() == true;

        pageRenderMode = isStaticPage ? null : InteractiveServer;
    }
}

